    let _headerMatch = _headerSecret.length === _authSecret.length && _headerSecret.length > 0;
    for (let i = 0; i < _authSecret.length; i++) {
      if (_headerSecret.charCodeAt(i) !== _authSecret.charCodeAt(i)) {
