async function retry(fn, n = 2, ms = 800) {
  for (let i = 0; i <= n; i++) {
    try { return await fn(); }
    catch (e) {
      if (i === n) throw e;
      await new Promise(r => setTimeout(r, ms * Math.pow(2, i)));
    }
  }
}

