      } else {
        state._pendingGTCCloses[ticker] = entry;
        stillOpen.push(ticker);
      }
    }

  } catch (err) {
    console.log('[GTC-CHECK v5.16] Error on ' + ticker + ': ' + err.message);
    stillOpen.push(ticker);
  }
}

