// QTP_ENTRY_QUALITY_AI_CONFLICT_GUARD + BACKTEST_ENFORCEMENT v4.2.12 — live entry-quality filter
// Additive hardening: VC >=7 remains locked upstream. Blocks only low-quality new entries before Alpaca.
// Rules: bias >=68 AND secondary confirmation AND no explicit AI/HOLD/low-confidence conflict AND required backtest data valid.
const scored = items.map(item => {
  const output = { ...(item.json || {}) };

  function num(v, fallback = 0) {
    if (v === undefined || v === null || String(v).trim() === '') return fallback;
