function sanitizeMD(text) {
  if (!text) return '';
  text = text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  let s = text;
  s = s.replace(/\*\*/g, '');
  s = s.replace(/\*/g, '');
  s = s.replace(/__/g, '');
  s = s.replace(/_/g, ' ');
  s = s.replace(/`{3}[\s\S]*?`{3}/g, '');
  s = s.replace(/`/g, "'");
  s = s.replace(/\[([^\]]*?)\]\([^)]*?\)/g, '$1');
  s = s.replace(/\[/g, '(');
  s = s.replace(/\]/g, ')');
  s = s.replace(/~/g, '-');
  s = s.replace(/#/g, '');
  s = s.replace(/\n{3,}/g, NL + NL);
  return s.trim();
}

