    p._backtest_win_rate,
    p.backtest_win_rate,
    p.strat_win_rate,
    p.win_rate,
    p.bt_win_rate
  ), null);

  const status = first(
    p._backtest_status,
    p.backtest_status,
    sample === null || pf === null ? 'NO_BACKTEST_DATA' :
      (sample >= 100 && pf >= 1.2 ? 'BACKTEST_DATA_OK' : 'WEAK_BACKTEST_DATA')
