    return Number.isFinite(n) ? n : fallback;
  }
  function numOrNull(v) {
    if (v === undefined || v === null || String(v).trim() === '') return null;
    const n = Number(String(v).replace('%', '').trim());
    return Number.isFinite(n) ? n : null;
  }
  function txt(...vals) {
    for (const v of vals) {
